#include <bits/stdc++.h>
using namespace std;
int main(){
    const long long MOD = 1000000007;
    int n, S; cin >> n >> S;
    vector<int> c(n);
    for (auto &x : c) cin >> x;
    vector<long long> dp(S + 1, 0);
    dp[0] = 1;
    for (int x : c) for (int s = x; s <= S; s++) dp[s] = (dp[s] + dp[s - x]) % MOD;
    cout << dp[S] << '\n';
}
